from typing import List

def insert_sequence(sequence: List[int]) -> List[int]:
    while True:
        differences = [abs(a - b) for a, b in zip(sequence, sequence[1:])]
        if all(diff == 1 for diff in differences):
            break
        i = differences.index(max(differences))
        if sequence[i] < sequence[i+1]:
            sequence[i:i+2] = list(range(sequence[i]+1, sequence[i+1]))
        else:
            sequence[i:i+2] = list(range(sequence[i-1], sequence[i]))
    return sequence

