# read input string
s = input()

# use dynamic programming to find the maximum length of a contiguous substring of s that is a palindrome
# dp[i][j] is the maximum length of a contiguous substring of s[i:j] that is a palindrome
dp = [[0]*len(s) for i in range(len(s))]
for i in range(len(s)):
    dp[i][i] = 1
for i in range(1, len(s)):
    for j in range(len(s)-i):
        if s[j]==s[j+i] and dp[j+1][j+i-1]:
            dp[j][j+i] = i+1
# print maximum length of a contiguous substring of s that is a palindrome
print(max(dp[i][j] for i in range(len(s)) for j in range(i,len(s))))
